class PdfPKCS1Formatter(IPdfSignatureFormatter, Security_IPdfSignatureFormatter):
    """
    Pdf pkcs1 signature implementation.
    """

    @property
    def Properties(self) -> 'PdfSignatureProperties':
        """
        The signature properties.
        """
        GetDllLibPdf().spr_pdf_PdfPKCS1Formatter_get_Properties.argtypes = [c_void_p]
        GetDllLibPdf().spr_pdf_PdfPKCS1Formatter_get_Properties.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfPKCS1Formatter_get_Properties,self.Ptr)
        ret = None if intPtr == None else PdfSignatureProperties(intPtr)
        return ret


